    // 2. Add a method to write the log to file
    func log(message: String) {
        let dateFormatter = DateFormatter()
        dateFormatter.dateFormat = "yyyy-MM-dd HH:mm:ss.SSS"

        guard let url = logFileUrl else { return }
        
        // 3. Use a string interpolation and call the method to write to the file
        print("\(dateFormatter.string(from: Date()))  \(message)")
        do {
            try "\(dateFormatter.string(from: Date()))  \(message)\n".write(to: url, atomically: true, encoding: .utf8)
        } catch let error as NSError {
