        }
    }
}
// 4. Add a method to create the file in the directory path.
func startLogging() -> Void {
    guard let documentsPath = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first else { return }

    let logFilePath = documentsPath.appendingPathComponent("\(Logger.self)")
    let dateFormatter = DateFormatter()
    dateFormatter.dateFormat = "yyyyMMdd-HHmmss"
    
    do {
        try FileManager().createDirectory(at: documentsPath, withIntermediateDirectories: true)

        guard (FileManager.default.fileExists(atPath: logFilePath.absoluteString)) else {
            let url = logFilePath.appendingPathComponent("\(dateFormatter.string(from: Date())).log")

            Logger.shared.logFileUrl = url
        }
    } catch {
        print("An error occurred while creating the directory: \(error)")
    }
}

// 5. Add a method to stop logging when your module is deinitialized.
deinit {
    guard let logFileUrl = self.logFileUrl else { return }

    do {
        try FileManager().removeItem(atPath: logFileUrl.path)

        print("Logging finished")
    } catch let error as NSError {
        print("Failed to delete file : \(error)")
    }
}

